class DatabaseTransaction:
    def __init__(self, connection):
        self.connection = connection
        self._original_isolation_level = None

    def __enter__(self):
        if hasattr(self.connection, 'isolation_level'):
            self._original_isolation_level = self.connection.isolation_level
            self.connection.isolation_level = None

        self.connection.execute("BEGIN")
        return self.connection.cursor()

    def __exit__(self, exc_type, exc_val, exc_tb):
        try:
            if exc_type is None:
                self.connection.commit()
            else:
                self.connection.rollback()
        finally:
            if hasattr(self.connection, 'isolation_level') and \
               self._original_isolation_level is not None:
                self.connection.isolation_level = self._original_isolation_level
            return False
